# Cohen (1988) effect size guidelines
COHEN_GUIDELINES = {
    'small': 0.02,
    'medium': 0.15,
    'large': 0.35
}

# Power analysis parameters
N_PARTICIPANTS = 100
N_PREDICTORS = 3
ALPHA_CORRECTED = 0.0056  # Bonferroni corrected for 9 tests
BOOTSTRAP_ITERATIONS = 1000
RANDOM_SEED = 42

def interpret_cohens_f2(f2):
    """Apply Cohen (1988) interpretation guidelines to f² values."""
    if f2 >= COHEN_GUIDELINES['large']:
        return 'Large'
    elif f2 >= COHEN_GUIDELINES['medium']:
        return 'Medium'
    elif f2 >= COHEN_GUIDELINES['small']:
        return 'Small'
    else:
        return 'Negligible'

def bootstrap_cohens_f2_ci(r2_values, n_bootstrap=1000, random_state=42):
    """Bootstrap confidence intervals for Cohen's f² from R² values."""
    np.random.seed(random_state)
    
    # Convert R² to f²
    f2_values = [r2 / (1 - r2) if r2 < 1.0 else np.inf for r2 in r2_values]
    
    # Bootstrap resampling
    bootstrap_f2 = []
    for _ in range(n_bootstrap):
        # Resample with replacement (simulating sampling variability)
        resampled_r2 = np.random.choice(r2_values, size=len(r2_values), replace=True)
        # Add small noise to simulate model variability
        resampled_r2 = np.clip(resampled_r2 + np.random.normal(0, 0.01, len(resampled_r2)), 0, 0.99)
        # Compute f² for resampled values
        bootstrap_f2.extend([r2 / (1 - r2) for r2 in resampled_r2])
    
    # Compute confidence intervals
    ci_lower = np.percentile(bootstrap_f2, 2.5)
    ci_upper = np.percentile(bootstrap_f2, 97.5)
    
    return ci_lower, ci_upper

def compute_minimum_detectable_effect(n, k_predictors, alpha, power=0.8):
    """Compute minimum detectable f² for given power using statsmodels."""
    try:
        # Use F-test power analysis
        # For regression: H0: R² = 0 vs H1: R² > 0
        df_num = k_predictors
        df_denom = n - k_predictors - 1
        
        # Compute required effect size (f²) for desired power
        # Using non-central F distribution
        from scipy.stats import f, ncf
        
        # Critical F value
        f_crit = f.ppf(1 - alpha, df_num, df_denom)
        
        # Binary search for non-centrality parameter that gives desired power
        def power_for_ncp(ncp):
            return 1 - ncf.cdf(f_crit, df_num, df_denom, ncp)
        
        # Binary search
        ncp_low, ncp_high = 0.01, 100
        for _ in range(50):  # Max iterations
            ncp_mid = (ncp_low + ncp_high) / 2
            power_mid = power_for_ncp(ncp_mid)
            
            if abs(power_mid - power) < 0.001:
                break
                
            if power_mid < power:
                ncp_low = ncp_mid
            else:
                ncp_high = ncp_mid
        
        # Convert non-centrality parameter back to f²
        # ncp = f² × (df_num + df_denom + 1)
        f2_min = ncp_mid / (df_num + df_denom + 1)
        return f2_min
        
    except Exception as e:
        log(f"[WARNING] Minimum detectable effect calculation failed: {e}")
        return np.nan

