        # Extract unique R² values per model
        model_r2 = results_df.groupby('model')['r_squared'].first().reset_index()
        log(f"[INFO] Found {len(model_r2)} models with R² values:")
        for _, row in model_r2.iterrows():
            log(f"  - {row['model']}: R² = {row['r_squared']:.4f}")

        # =========================================================================
        # STEP 2: Compute Cohen's f² Effect Sizes
        # =========================================================================
        # Tool: Direct computation f² = R² / (1 - R²)
        # What it does: Convert variance explained (R²) to effect size (f²)
        # Expected output: Effect sizes with Cohen (1988) interpretations

        log("[ANALYSIS] Computing Cohen's f² effect sizes...")
        effect_sizes = []

        for _, row in model_r2.iterrows():
            model_name = row['model']
            r2 = row['r_squared']
            
            # Compute Cohen's f² = R² / (1 - R²)
            if r2 >= 1.0:
                f2 = np.inf
                log(f"[WARNING] {model_name}: R² ≥ 1.0, f² = infinity")
            else:
                f2 = r2 / (1 - r2)
            
            # Apply Cohen (1988) interpretation
            interpretation = interpret_cohens_f2(f2)
            
            # Compute post-hoc power with observed f²
            if np.isfinite(f2):
                power_observed = compute_post_hoc_power(
                    n=N_PARTICIPANTS,
                    k_predictors=N_PREDICTORS, 
                    r2=r2,
                    alpha=ALPHA_CORRECTED
                )
            else:
                power_observed = 1.0  # Perfect power for infinite effect
            
            effect_sizes.append({
                'model': model_name,
                'r_squared': r2,
                'cohens_f2': f2,
                'power_observed': power_observed,
                'effect_interpretation': interpretation
            })
            
            log(f"[COMPUTED] {model_name}: f² = {f2:.4f} ({interpretation}), Power = {power_observed:.3f}")

        # =========================================================================
        # STEP 3: Bootstrap Confidence Intervals
        # =========================================================================
        # What it does: Estimate uncertainty in f² values using bootstrap resampling
        # Purpose: Provide confidence intervals for effect size estimates

        log("[BOOTSTRAP] Computing bootstrap confidence intervals...")
        
        for effect in effect_sizes:
            model_name = effect['model']
            r2 = effect['r_squared']
            
            # Bootstrap CIs (using model-level R² with simulated variability)
            try:
                ci_lower, ci_upper = bootstrap_cohens_f2_ci(
                    r2_values=[r2],  # Single R² value per model
                    n_bootstrap=BOOTSTRAP_ITERATIONS,
                    random_state=RANDOM_SEED
                )
                
                effect['f2_ci_lower'] = ci_lower
                effect['f2_ci_upper'] = ci_upper
                
                log(f"[BOOTSTRAP] {model_name}: 95% CI = [{ci_lower:.4f}, {ci_upper:.4f}]")
                
            except Exception as e:
                log(f"[WARNING] Bootstrap CI failed for {model_name}: {e}")
                effect['f2_ci_lower'] = np.nan
                effect['f2_ci_upper'] = np.nan

